payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "材料与硬件攻坚",
      "description": "完成仿生柔性传感器微结构设计、液态金属-聚氨酯复合材料制备及信号标定，构建0.1mm级空间分辨率的混合传感架构。"
    },
    {
      "date": "第3月",
      "title": "算法开发与融合协议构建",
      "description": "开发分层CNN-LSTM手势识别模型，结合自适应滑动窗口分割与噪声抑制模块，实测准确率>98.2%；同步建立多模态统一时空对齐协议，提升跨平台部署效率60%。"
    },
    {
      "date": "第4月",
      "title": "系统集成与闭环搭建",
      "description": "完成软硬件联调，嵌入微型电磁致动器阵列与半导体温控模块，实现压力/温度微秒级调控，构建感知-意图-反馈交互闭环。"
    },
    {
      "date": "第5–6月",
      "title": "多场景验证与优化",
      "description": "依托H-Box全息舱、李未可眼镜等平台，在工业远程操控与虚拟实训场景开展压力测试，迭代优化用户体验，形成可复用交互标准接口。"
    }
  ]
}

